/**
 * The primary UniFFI-exported object. Swift holds one of these for the
 * lifetime of the app session.
 */
open class WalletService: WalletServiceProtocol, @unchecked Sendable {
    fileprivate let pointer: UnsafeMutableRawPointer!

    /// Used to instantiate a [FFIObject] without an actual pointer, for fakes in tests, mostly.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public struct NoPointer {
        public init() {}
    }

    // TODO: We'd like this to be `private` but for Swifty reasons,
    // we can't implement `FfiConverter` without making this `required` and we can't
    // make it `required` without making it `public`.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    required public init(unsafeFromRawPointer pointer: UnsafeMutableRawPointer) {
        self.pointer = pointer
    }

    // This constructor can be used to instantiate a fake object.
    // - Parameter noPointer: Placeholder value so we can have a constructor separate from the default empty one that may be implemented for classes extending [FFIObject].
    //
    // - Warning:
    //     Any object instantiated with this constructor cannot be passed to an actual Rust-backed object. Since there isn't a backing [Pointer] the FFI lower functions will crash.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public init(noPointer: NoPointer) {
        self.pointer = nil
    }

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public func uniffiClonePointer() -> UnsafeMutableRawPointer {
        return try! rustCall { uniffi_spectra_core_fn_clone_walletservice(self.pointer, $0) }
    }
public convenience init(endpointsJson: String)throws  {
    let pointer =
        try rustCallWithError(FfiConverterTypeSpectraBridgeError_lift) {
    uniffi_spectra_core_fn_constructor_walletservice_new(
        FfiConverterString.lower(endpointsJson),$0
    )
}
    self.init(unsafeFromRawPointer: pointer)
}

    deinit {
        guard let pointer = pointer else {
            return
        }

        try! rustCall { uniffi_spectra_core_fn_free_walletservice(pointer, $0) }
    }

    

    
    /**
     * Record the cursor returned after a successful cursor-based fetch (UTXO
     * chains). Pass `None` when the chain confirms there are no more pages —
     * this marks the chain as exhausted.
     */
open func advanceHistoryCursor(chainId: UInt32, walletId: String, nextCursor: String?)  {try! rustCall() {
    uniffi_spectra_core_fn_method_walletservice_advance_history_cursor(self.uniffiClonePointer(),
        FfiConverterUInt32.lower(chainId),
        FfiConverterString.lower(walletId),
        FfiConverterOptionString.lower(nextCursor),$0
    )
}
}
    
    /**
     * Increment the page counter after a successful page-based fetch (EVM,
     * etc.). Pass `is_last = true` when the returned page was empty or the
     * chain indicated no next page.
     */
open func advanceHistoryPage(chainId: UInt32, walletId: String, isLast: Bool)  {try! rustCall() {
    uniffi_spectra_core_fn_method_walletservice_advance_history_page(self.uniffiClonePointer(),
        FfiConverterUInt32.lower(chainId),
        FfiConverterString.lower(walletId),
        FfiConverterBool.lower(isLast),$0
    )
}
}
    
