#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeWalletService: FfiConverter {

    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = WalletService

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> WalletService {
        return WalletService(unsafeFromRawPointer: pointer)
    }

    public static func lower(_ value: WalletService) -> UnsafeMutableRawPointer {
        return value.uniffiClonePointer()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> WalletService {
        let v: UInt64 = try readInt(&buf)
        // The Rust code won't compile if a pointer won't fit in a UInt64.
        // We have to go via `UInt` because that's the thing that's the size of a pointer.
        let ptr = UnsafeMutableRawPointer(bitPattern: UInt(truncatingIfNeeded: v))
        if (ptr == nil) {
            throw UniffiInternalError.unexpectedNullPointer
        }
        return try lift(ptr!)
    }

    public static func write(_ value: WalletService, into buf: inout [UInt8]) {
        // This fiddling is because `Int` is the thing that's the same size as a pointer.
        // The Rust code won't compile if a pointer won't fit in a `UInt64`.
        writeInt(&buf, UInt64(bitPattern: Int64(Int(bitPattern: lower(value)))))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeWalletService_lift(_ pointer: UnsafeMutableRawPointer) throws -> WalletService {
    return try FfiConverterTypeWalletService.lift(pointer)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeWalletService_lower(_ value: WalletService) -> UnsafeMutableRawPointer {
    return FfiConverterTypeWalletService.lower(value)
}




public struct ActiveMaintenancePlan {
    public var refreshPendingTransactions: Bool
    public var refreshLivePrices: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(refreshPendingTransactions: Bool, refreshLivePrices: Bool) {
        self.refreshPendingTransactions = refreshPendingTransactions
        self.refreshLivePrices = refreshLivePrices
    }
}

#if compiler(>=6)
extension ActiveMaintenancePlan: Sendable {}
#endif


extension ActiveMaintenancePlan: Equatable, Hashable {
    public static func ==(lhs: ActiveMaintenancePlan, rhs: ActiveMaintenancePlan) -> Bool {
        if lhs.refreshPendingTransactions != rhs.refreshPendingTransactions {
            return false
        }
        if lhs.refreshLivePrices != rhs.refreshLivePrices {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(refreshPendingTransactions)
        hasher.combine(refreshLivePrices)
    }
}



