public struct ActiveMaintenancePlanRequest {
    public var nowUnix: Double
    public var lastPendingTransactionRefreshAtUnix: Double?
    public var lastLivePriceRefreshAtUnix: Double?
    public var hasPendingTransactionMaintenanceWork: Bool
    public var shouldRunScheduledPriceRefresh: Bool
    public var pendingRefreshInterval: Double
    public var priceRefreshInterval: Double

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(nowUnix: Double, lastPendingTransactionRefreshAtUnix: Double?, lastLivePriceRefreshAtUnix: Double?, hasPendingTransactionMaintenanceWork: Bool, shouldRunScheduledPriceRefresh: Bool, pendingRefreshInterval: Double, priceRefreshInterval: Double) {
        self.nowUnix = nowUnix
        self.lastPendingTransactionRefreshAtUnix = lastPendingTransactionRefreshAtUnix
        self.lastLivePriceRefreshAtUnix = lastLivePriceRefreshAtUnix
        self.hasPendingTransactionMaintenanceWork = hasPendingTransactionMaintenanceWork
        self.shouldRunScheduledPriceRefresh = shouldRunScheduledPriceRefresh
        self.pendingRefreshInterval = pendingRefreshInterval
        self.priceRefreshInterval = priceRefreshInterval
    }
}

#if compiler(>=6)
extension ActiveMaintenancePlanRequest: Sendable {}
#endif


extension ActiveMaintenancePlanRequest: Equatable, Hashable {
    public static func ==(lhs: ActiveMaintenancePlanRequest, rhs: ActiveMaintenancePlanRequest) -> Bool {
        if lhs.nowUnix != rhs.nowUnix {
            return false
        }
        if lhs.lastPendingTransactionRefreshAtUnix != rhs.lastPendingTransactionRefreshAtUnix {
            return false
        }
        if lhs.lastLivePriceRefreshAtUnix != rhs.lastLivePriceRefreshAtUnix {
            return false
        }
        if lhs.hasPendingTransactionMaintenanceWork != rhs.hasPendingTransactionMaintenanceWork {
            return false
        }
        if lhs.shouldRunScheduledPriceRefresh != rhs.shouldRunScheduledPriceRefresh {
            return false
        }
        if lhs.pendingRefreshInterval != rhs.pendingRefreshInterval {
            return false
        }
        if lhs.priceRefreshInterval != rhs.priceRefreshInterval {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(nowUnix)
        hasher.combine(lastPendingTransactionRefreshAtUnix)
        hasher.combine(lastLivePriceRefreshAtUnix)
        hasher.combine(hasPendingTransactionMaintenanceWork)
        hasher.combine(shouldRunScheduledPriceRefresh)
        hasher.combine(pendingRefreshInterval)
        hasher.combine(priceRefreshInterval)
    }
}



