public enum StateCommand {
    
    case replaceState(state: CoreAppState
    )
    case upsertWallet(wallet: WalletSummary
    )
    case selectWallet(walletId: String
    )
    case removeWallet(walletId: String
    )
    case setPreferredLocale(localeIdentifier: String
    )
    case setFiatCurrency(fiatCurrencyCode: String
    )
    case setDiagnosticsEnabled(isEnabled: Bool
    )
}


#if compiler(>=6)
extension StateCommand: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeStateCommand: FfiConverterRustBuffer {
    typealias SwiftType = StateCommand

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> StateCommand {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .replaceState(state: try FfiConverterTypeCoreAppState.read(from: &buf)
        )
        
        case 2: return .upsertWallet(wallet: try FfiConverterTypeWalletSummary.read(from: &buf)
        )
        
        case 3: return .selectWallet(walletId: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .removeWallet(walletId: try FfiConverterString.read(from: &buf)
        )
        
        case 5: return .setPreferredLocale(localeIdentifier: try FfiConverterString.read(from: &buf)
        )
        
        case 6: return .setFiatCurrency(fiatCurrencyCode: try FfiConverterString.read(from: &buf)
        )
        
        case 7: return .setDiagnosticsEnabled(isEnabled: try FfiConverterBool.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: StateCommand, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .replaceState(state):
            writeInt(&buf, Int32(1))
            FfiConverterTypeCoreAppState.write(state, into: &buf)
            
        
        case let .upsertWallet(wallet):
            writeInt(&buf, Int32(2))
            FfiConverterTypeWalletSummary.write(wallet, into: &buf)
            
        
        case let .selectWallet(walletId):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(walletId, into: &buf)
            
        
        case let .removeWallet(walletId):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(walletId, into: &buf)
            
        
        case let .setPreferredLocale(localeIdentifier):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(localeIdentifier, into: &buf)
            
        
        case let .setFiatCurrency(fiatCurrencyCode):
            writeInt(&buf, Int32(6))
            FfiConverterString.write(fiatCurrencyCode, into: &buf)
            
        
        case let .setDiagnosticsEnabled(isEnabled):
            writeInt(&buf, Int32(7))
            FfiConverterBool.write(isEnabled, into: &buf)
            
        }
    }
}


